// ============================================================
//  Cloudflare Worker — server lisensi Roblox + panel admin + bot Discord.
//
//  ---- KONFIGURASI (semua lewat dashboard Cloudflare, tak perlu edit file) ----
//  Binding KV (wajib):
//    LICENSE_KV             - namespace KV tempat data disimpan.
//  Secrets (Settings -> Variables and Secrets, pilih tipe "Secret"):
//    ADMIN_KEY              (WAJIB)    - kunci masuk panel admin. Buat panjang & acak.
//    DISCORD_PUBLIC_KEY     (opsional) - wajib hanya untuk command /own.
//    DISCORD_BOT_TOKEN      (opsional) - wajib hanya untuk command /own.
//    DISCORD_APPLICATION_ID (opsional) - wajib hanya untuk command /own.
//
//  ---- Struktur data KV (key "db") ----
//    { products: { <pid>: { name, createdAt, users:{}, groups:{} } },
//      settings: { discordWebhook, discordBotName, discordBotAvatar,
//                  discordAlertUnauthorized } }
// ============================================================

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;

    try {
      if (path === "/" && method === "GET") {
        return new Response("License server aktif. Buka /admin untuk panel.");
      }

      // ---- dipanggil dari dalam game Roblox ----
      if (path === "/api/verify" && method === "POST") {
        const body = await readJson(request);
        const pid = typeof body.productId === "string" ? body.productId : "";
        const db = await loadDB(env);
        // status: "licensed" (pasti berlisensi) | "denied" (pasti ditolak) |
        //         "unknown" (tidak bisa dipastikan sekarang -> JANGAN kick).
        const result = pid ? await authorize(env, db, pid, body.creatorId, body.creatorType) : { status: "denied" };
        if (result.status === "denied") {
          // (opsional) beri tahu penjual HANYA saat benar-benar ditolak, bukan saat ragu.
          ctx.waitUntil(alertUnauthorized(db, body).catch(() => {}));
        }
        // Kompat snippet lama: "unknown" dipetakan ke authorized:true supaya
        // gangguan sesaat (mis. API grup Roblox nge-throttle) TIDAK meng-kick
        // pembeli sah. Snippet baru membaca "status" untuk keputusan yang tepat.
        const authorizedBool = result.status === "licensed" || result.status === "unknown";
        // ts dalam DETIK epoch; dipakai snippet Lua untuk menolak respon basi.
        return json({ authorized: authorizedBool, status: result.status, nonce: body.nonce, ts: Math.floor(Date.now() / 1000) });
      }

      // ---- endpoint publik untuk bot Discord (Interactions Endpoint URL) ----
      if (path === "/discord/interactions" && method === "POST") {
        return handleDiscordInteraction(request, env, ctx);
      }

      // ---- semua endpoint admin butuh kunci admin ----
      if (path.startsWith("/api/admin/")) {
        if (!isAdmin(request, env)) return json({ error: "unauthorized" }, 401);
      }

      // ---- admin: daftar semua (produk + settings) ----
      if (path === "/api/admin/list" && method === "GET") {
        return json(await loadDB(env));
      }

      // ---- admin: buat produk baru (pid = kode acak) ----
      if (path === "/api/admin/product/create" && method === "POST") {
        const { name } = await readJson(request);
        const nm = (name || "").trim();
        if (!nm) return json({ error: "nama produk wajib" }, 400);
        const db = await loadDB(env);
        let pid = genId();
        while (db.products[pid]) pid = genId();
        db.products[pid] = { name: nm, createdAt: new Date().toISOString(), users: {}, groups: {} };
        await saveDB(env, db);
        return json({ ok: true, productId: pid });
      }

      // ---- admin: perbarui detail produk (nama, harga, gambar, link, deskripsi) ----
      if (path === "/api/admin/product/update" && method === "POST") {
        const { productId, name, price, imageUrl, link, description } = await readJson(request);
        const db = await loadDB(env);
        const p = db.products[productId];
        if (!p) return json({ error: "produk tidak ada" }, 404);
        if (name !== undefined) { const nm = (name || "").trim(); if (nm) p.name = nm; }
        if (price !== undefined) p.price = (price || "").trim();
        if (imageUrl !== undefined) p.imageUrl = (imageUrl || "").trim();
        if (link !== undefined) p.link = (link || "").trim();
        if (description !== undefined) p.description = (description || "").trim();
        await saveDB(env, db);
        return json({ ok: true });
      }

      // ---- admin: hapus produk (beserta seluruh whitelistnya) ----
      if (path === "/api/admin/product/delete" && method === "POST") {
        const { productId } = await readJson(request);
        const db = await loadDB(env);
        if (!db.products[productId]) return json({ error: "produk tidak ada" }, 404);
        delete db.products[productId];
        await saveDB(env, db);
        return json({ ok: true });
      }

      // ---- admin: cari tahu username/ID Roblox itu valid & terdaftar atau tidak ----
      if (path === "/api/admin/resolve" && method === "POST") {
        const { input } = await readJson(request);
        const r = await resolveTarget(input);
        return json(r);
      }

      // ---- admin: beri whitelist (username otomatis dari Roblox) ----
      if (path === "/api/admin/grant" && method === "POST") {
        let { productId, userId, username, note } = await readJson(request);
        if (!productId || !userId) return json({ error: "productId & userId wajib" }, 400);
        const db = await loadDB(env);
        const p = db.products[productId];
        if (!p) return json({ error: "produk tidak ada" }, 404);
        if (!username) username = await fetchUsername(userId);
        const existing = p.users[String(userId)] || {};
        const isNew = !existing.grantedAt;
        p.users[String(userId)] = {
          username: username || existing.username || null,
          note: note || existing.note || null,
          active: true,
          grantedAt: existing.grantedAt || new Date().toISOString(),
        };
        await saveDB(env, db);
        if (isNew) {
          // log ke Discord hanya untuk ID yang benar-benar baru
          ctx.waitUntil(notifyDiscord(db, p, productId, String(userId), username).catch(() => {}));
        }
        return json({ ok: true, username: username || null, isNew });
      }

      // ---- admin: aktifkan / nonaktifkan satu whitelist ----
      if (path === "/api/admin/toggle" && method === "POST") {
        const { productId, userId, active } = await readJson(request);
        const db = await loadDB(env);
        const p = db.products[productId];
        if (!p || !p.users[String(userId)]) return json({ error: "tidak ada" }, 404);
        p.users[String(userId)].active = !!active;
        await saveDB(env, db);
        return json({ ok: true });
      }

      // ---- admin: cabut / hapus permanen ----
      if (path === "/api/admin/revoke" && method === "POST") {
        const { productId, userId, groupId, hard } = await readJson(request);
        const db = await loadDB(env);
        const p = db.products[productId];
        if (!p) return json({ error: "produk tidak ada" }, 404);
        if (userId) { if (hard) delete p.users[String(userId)]; else if (p.users[String(userId)]) p.users[String(userId)].active = false; }
        if (groupId) { if (hard) delete p.groups[String(groupId)]; else if (p.groups[String(groupId)]) p.groups[String(groupId)].active = false; }
        await saveDB(env, db);
        return json({ ok: true });
      }

      // ---- admin: ambil username + avatar dari Roblox (via server, bebas CORS) ----
      if (path === "/api/admin/enrich" && method === "POST") {
        const { userIds } = await readJson(request);
        if (!Array.isArray(userIds) || userIds.length === 0) return json({});
        const ids = userIds.map((x) => String(x)).filter((x) => /^[0-9]+$/.test(x)).slice(0, 100);
        if (ids.length === 0) return json({});
        const out = {};
        try {
          const r = await fetch("https://users.roblox.com/v1/users", {
            method: "POST",
            headers: { "content-type": "application/json" },
            body: JSON.stringify({ userIds: ids.map(Number), excludeBannedUsers: false }),
          });
          if (r.ok) { const j = await r.json(); for (const u of (j.data || [])) out[String(u.id)] = { username: u.name, displayName: u.displayName }; }
        } catch (e) {}
        try {
          const r = await fetch("https://thumbnails.roblox.com/v1/users/avatar-headshot?userIds=" + ids.join(",") + "&size=150x150&format=Png&isCircular=false");
          if (r.ok) { const j = await r.json(); for (const a of (j.data || [])) { out[String(a.targetId)] = out[String(a.targetId)] || {}; out[String(a.targetId)].avatarUrl = a.imageUrl; } }
        } catch (e) {}
        return json(out);
      }

      // ---- admin: baca / simpan pengaturan (webhook + identitas bot Discord) ----
      if (path === "/api/admin/settings" && method === "GET") {
        const db = await loadDB(env);
        const s = db.settings || {};
        return json({
          discordWebhook: s.discordWebhook || "",
          discordBotName: s.discordBotName || "",
          discordBotAvatar: s.discordBotAvatar || "",
          discordAlertUnauthorized: !!s.discordAlertUnauthorized,
          discordGuildId: s.discordGuildId || "",
          hasSlashCommandSecrets: !!(env.DISCORD_APPLICATION_ID && env.DISCORD_BOT_TOKEN && env.DISCORD_PUBLIC_KEY),
        });
      }
      if (path === "/api/admin/settings" && method === "POST") {
        const { discordWebhook, discordBotName, discordBotAvatar, discordAlertUnauthorized, discordGuildId } = await readJson(request);
        const db = await loadDB(env);
        db.settings = db.settings || {};
        if (discordWebhook !== undefined) db.settings.discordWebhook = (discordWebhook || "").trim();
        if (discordBotName !== undefined) db.settings.discordBotName = (discordBotName || "").trim();
        if (discordBotAvatar !== undefined) db.settings.discordBotAvatar = (discordBotAvatar || "").trim();
        if (discordAlertUnauthorized !== undefined) db.settings.discordAlertUnauthorized = !!discordAlertUnauthorized;
        if (discordGuildId !== undefined) db.settings.discordGuildId = (discordGuildId || "").replace(/[^0-9]/g, "");
        await saveDB(env, db);
        return json({ ok: true });
      }

      // ---- admin: daftarkan command /own ke Discord (sekali klik) ----
      if (path === "/api/admin/discord/register-command" && method === "POST") {
        if (!env.DISCORD_APPLICATION_ID || !env.DISCORD_BOT_TOKEN) {
          return json({ error: "Secret DISCORD_APPLICATION_ID / DISCORD_BOT_TOKEN belum diset di Cloudflare." }, 400);
        }
        const cmd = [
          {
            name: "own",
            description: "Lihat produk yang lisensinya kamu miliki",
            options: [{ name: "akun", description: "Username atau User ID Roblox kamu", type: 3, required: true }],
          },
          {
            name: "products",
            description: "Lihat semua produk yang tersedia",
          },
        ];
        try {
          const db = await loadDB(env);
          const guildId = (db.settings && db.settings.discordGuildId) || "";
          // Guild = muncul SEKETIKA di server itu. Global = semua server tapi bisa ~1 jam.
          const endpoint = guildId
            ? "https://discord.com/api/v10/applications/" + env.DISCORD_APPLICATION_ID + "/guilds/" + guildId + "/commands"
            : "https://discord.com/api/v10/applications/" + env.DISCORD_APPLICATION_ID + "/commands";
          const r = await fetch(endpoint, {
            method: "PUT",
            headers: { authorization: "Bot " + env.DISCORD_BOT_TOKEN, "content-type": "application/json" },
            body: JSON.stringify(cmd),
          });
          if (!r.ok) { const t = await r.text(); return json({ error: "Discord menolak: " + t }, 400); }
          return json({ ok: true, scope: guildId ? "guild" : "global" });
        } catch (e) { return json({ error: String(e) }, 500); }
      }

      // ---- panel admin ----
      if (path === "/admin" && method === "GET") {
        return new Response(ADMIN_HTML, { headers: { "content-type": "text/html; charset=utf-8" } });
      }

      return new Response("Not found", { status: 404 });
    } catch (err) {
      return json({ error: String(err) }, 500);
    }
  },
};

// ---------- util ----------
function json(obj, status = 200) {
  return new Response(JSON.stringify(obj), { status, headers: { "content-type": "application/json" } });
}
async function readJson(request) { try { return await request.json(); } catch { return {}; } }
function sleep(ms) { return new Promise((r) => setTimeout(r, ms)); }
function isHttpUrl(u) { return typeof u === "string" && /^https?:\/\/\S+$/i.test(u.trim()); }
// daftar nama produk yang dimiliki (di-whitelist) oleh satu userId
function productsOwnedBy(db, userId) {
  const uid = String(userId);
  const out = [];
  for (const pid of Object.keys(db.products || {})) {
    const p = db.products[pid];
    const u = p.users && p.users[uid];
    if (u) out.push({ name: p.name || "Produk", active: u.active !== false });
  }
  return out;
}
function timingSafeEqual(a, b) {
  const enc = new TextEncoder();
  const ba = enc.encode(String(a == null ? "" : a));
  const bb = enc.encode(String(b == null ? "" : b));
  let diff = ba.length ^ bb.length;
  const n = Math.max(ba.length, bb.length);
  for (let i = 0; i < n; i++) diff |= (ba[i] || 0) ^ (bb[i] || 0);
  return diff === 0;
}
function isAdmin(request, env) {
  if (!env.ADMIN_KEY) return false; // tanpa ADMIN_KEY, panel terkunci total
  return timingSafeEqual(request.headers.get("x-admin-key"), env.ADMIN_KEY);
}

function genId() {
  const c = "abcdefghijkmnpqrstuvwxyz23456789";
  let s = "";
  const a = crypto.getRandomValues(new Uint8Array(12));
  for (let i = 0; i < 12; i++) s += c[a[i] % c.length];
  return s;
}

async function loadDB(env) {
  const raw = await env.LICENSE_KV.get("db");
  let db = raw ? JSON.parse(raw) : {};
  // migrasi dari format lama (produk sebagai key paling atas) -> { products, settings }
  if (!db.products) {
    const products = {};
    for (const k of Object.keys(db)) {
      if (k === "products" || k === "settings") continue;
      const v = db[k];
      if (v && (v.users || v.groups)) {
        products[k] = { name: k, createdAt: new Date().toISOString(), users: v.users || {}, groups: v.groups || {} };
      }
    }
    db = { products, settings: db.settings || {} };
  }
  if (!db.settings) db.settings = {};
  return db;
}
async function saveDB(env, db) { await env.LICENSE_KV.put("db", JSON.stringify(db)); }

// fetch ke API Roblox dengan retry pada 429/5xx/gangguan jaringan.
// Roblox sering menolak sesaat (rate limit) dari IP Cloudflare -> retry menghilangkan
// "tidak ditemukan" palsu. throws bila SEMUA percobaan gagal (dibedakan dari 200-kosong).
async function robloxFetch(url, options, tries = 4) {
  const opt = options || {};
  opt.headers = Object.assign({
    accept: "application/json",
    "user-agent": "Mozilla/5.0 (compatible; LicensePanel/1.0)",
  }, opt.headers || {});
  let lastErr = null;
  for (let i = 0; i < tries; i++) {
    try {
      const r = await fetch(url, opt);
      if (r.ok) return r;                       // sukses
      if (r.status === 404) return r;           // benar-benar tidak ada -> jangan retry
      lastErr = new Error("HTTP " + r.status);  // 429/5xx -> retry
    } catch (e) { lastErr = e; }                // jaringan -> retry
    if (i < tries - 1) await sleep(300 * (i + 1) + Math.floor(Math.random() * 200));
  }
  throw lastErr || new Error("roblox fetch gagal");
}

// -> string username, null (tidak ada), atau throw (gagal cek sementara)
async function fetchUsername(id) {
  const r = await robloxFetch("https://users.roblox.com/v1/users", {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({ userIds: [Number(id)], excludeBannedUsers: false }),
  });
  if (!r.ok) return null;
  const j = await r.json();
  return (j.data && j.data[0]) ? j.data[0].name : null;
}
// avatar tidak kritikal: kalau gagal, cukup kembalikan null (jangan sampai gagalkan validasi)
async function fetchAvatar(id) {
  try {
    const r = await robloxFetch("https://thumbnails.roblox.com/v1/users/avatar-headshot?userIds=" + id + "&size=150x150&format=Png&isCircular=false", {}, 3);
    if (r.ok) { const j = await r.json(); if (j.data && j.data[0]) return j.data[0].imageUrl; }
  } catch (e) {}
  return null;
}
// Ambil pemilik grup dari Roblox dengan beberapa kali percobaan singkat.
// Mengembalikan null bila SEMUA percobaan gagal (bukan berarti "tak ada pemilik",
// melainkan "tak bisa dipastikan sekarang").
async function groupOwner(id) {
  for (let attempt = 0; attempt < 3; attempt++) {
    try {
      const r = await fetch("https://groups.roblox.com/v1/groups/" + id, {
        headers: { accept: "application/json" },
      });
      if (r.ok) {
        const j = await r.json();
        return j && j.owner ? String(j.owner.userId) : null;
      }
      // 429/5xx = throttle/gangguan sementara -> coba lagi. 404 = grup benar2 tak ada.
      if (r.status === 404) return null;
    } catch { /* jaringan gagal -> coba lagi */ }
    if (attempt < 2) await sleep(250 * (attempt + 1));
  }
  return null; // gagal dipastikan
}

const OWNER_TTL_MS = 24 * 60 * 60 * 1000; // segarkan cache pemilik grup tiap 24 jam

// Resolusi pemilik grup yang TAHAN GANGGUAN:
//  - pakai cache KV bila masih segar,
//  - kalau perlu ambil ulang; bila gagal, PAKAI cache lama (stale) supaya
//    game pembeli sah tidak ikut mati saat API grup Roblox sedang bermasalah,
//  - known:false HANYA bila belum pernah ada cache DAN pengambilan gagal.
async function resolveGroupOwner(env, groupId) {
  const key = "owner:" + groupId;
  let cached = null;
  try { const raw = await env.LICENSE_KV.get(key); if (raw) cached = JSON.parse(raw); } catch {}
  if (cached && cached.owner && (Date.now() - (cached.at || 0) < OWNER_TTL_MS)) {
    return { owner: cached.owner, known: true }; // cache segar
  }
  const owner = await groupOwner(groupId);
  if (owner) {
    try { await env.LICENSE_KV.put(key, JSON.stringify({ owner, at: Date.now() })); } catch {}
    return { owner, known: true };
  }
  if (cached && cached.owner) return { owner: cached.owner, known: true }; // fallback stale
  return { owner: null, known: false }; // benar-benar tak bisa dipastikan
}

// Mengembalikan { status }:
//   "licensed" = berlisensi, "denied" = pasti ditolak, "unknown" = ragu (jangan kick).
async function authorize(env, db, productId, creatorId, creatorType) {
  const p = db.products && db.products[productId];
  if (!p) return { status: "denied" };
  creatorId = String(creatorId);
  if (creatorType === "User") {
    const u = p.users && p.users[creatorId];
    return { status: (u && u.active !== false) ? "licensed" : "denied" };
  }
  if (creatorType === "Group") {
    const g = p.groups && p.groups[creatorId];
    if (g && g.active !== false) return { status: "licensed" }; // grup di-whitelist langsung
    const { owner, known } = await resolveGroupOwner(env, creatorId);
    if (!known) return { status: "unknown" }; // tak bisa pastikan pemilik -> jangan kick
    const ok = owner && p.users && p.users[owner] && p.users[owner].active !== false;
    return { status: ok ? "licensed" : "denied" };
  }
  return { status: "denied" };
}

// ---------- ubah username ATAU User ID jadi identitas Roblox lengkap ----------
// Hasil: { found:true, ... } | { found:false } (benar2 tak ada) | { found:false, error:true } (gagal cek)
async function resolveTarget(input) {
  input = String(input == null ? "" : input).trim();
  if (!input) return { found: false };
  try {
    if (/^[0-9]+$/.test(input)) {
      const uname = await fetchUsername(input);
      if (!uname) return { found: false };
      const avatarUrl = await fetchAvatar(input);
      return { found: true, userId: input, username: uname, avatarUrl: avatarUrl || null };
    }
    const r = await robloxFetch("https://users.roblox.com/v1/usernames/users", {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ usernames: [input], excludeBannedUsers: false }),
    });
    if (r.ok) {
      const j = await r.json();
      if (j.data && j.data[0]) {
        const id = String(j.data[0].id);
        const avatarUrl = await fetchAvatar(id);
        return { found: true, userId: id, username: j.data[0].name, avatarUrl: avatarUrl || null };
      }
      return { found: false }; // Roblox menjawab, tapi memang tidak ada
    }
    return { found: false, error: true };
  } catch (e) {
    return { found: false, error: true }; // gangguan sementara -> minta coba lagi, jangan bilang "tidak ada"
  }
}

// ---------- kirim log ke Discord (webhook) ----------
async function notifyDiscord(db, product, pid, userId, username) {
  const hook = db.settings && db.settings.discordWebhook;
  if (!hook) return;
  const avatar = await fetchAvatar(userId);
  const botName = (db.settings && db.settings.discordBotName) || "License Log";
  const botAvatar = (db.settings && db.settings.discordBotAvatar) || undefined;
  // Semua produk yang dimiliki ID ini (bisa lebih dari satu).
  const owned = productsOwnedBy(db, userId);
  const productValue = owned.length
    ? owned.map((o) => "\u27a4 " + o.name + (o.active ? "" : " _(nonaktif)_")).join("\n")
    : "\u27a4 " + ((product && product.name) || "Produk");
  const payload = {
    username: botName,
    avatar_url: botAvatar,
    embeds: [{
      title: "Whitelist baru ditambahkan",
      color: 3066993,
      thumbnail: avatar ? { url: avatar } : undefined,
      fields: [
        { name: owned.length > 1 ? "Produk (" + owned.length + ")" : "Produk", value: productValue, inline: true },
        { name: "User", value: (username || "(tidak diketahui)") + "\n`" + userId + "`", inline: true },
        { name: "Profil", value: "https://www.roblox.com/users/" + userId + "/profile", inline: false },
      ],
      timestamp: new Date().toISOString(),
    }],
  };
  await fetch(hook, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify(payload),
  });
}

// ---------- (opsional) peringatan saat game TAK berlisensi mencoba jalan ----------
const _alertSeen = new Map(); // throttle in-memory per isolate: key -> waktu terakhir (ms)
function _throttle(key, ms) {
  const now = Date.now();
  const last = _alertSeen.get(key) || 0;
  if (now - last < ms) return false;
  _alertSeen.set(key, now);
  if (_alertSeen.size > 500) { let i = 0; for (const k of _alertSeen.keys()) { _alertSeen.delete(k); if (++i >= 250) break; } }
  return true;
}
async function alertUnauthorized(db, body) {
  const s = db.settings || {};
  if (!s.discordAlertUnauthorized || !s.discordWebhook) return;
  const pid = String(body.productId || "");
  const p = db.products && db.products[pid];
  if (!p) return; // hanya untuk produk yang memang ada
  const creatorId = String(body.creatorId || "?");
  if (!_throttle(pid + ":" + creatorId, 60 * 60 * 1000)) return; // maks 1x / jam / game
  const placeId = body.placeId ? String(body.placeId) : null;
  const payload = {
    username: (s.discordBotName || "License Log"),
    avatar_url: s.discordBotAvatar || undefined,
    embeds: [{
      title: "Percobaan pemakaian TANPA lisensi",
      color: 15158332,
      fields: [
        { name: "Produk", value: "\u27a4 " + (p.name || pid), inline: true },
        { name: "Creator", value: (body.creatorType || "?") + " `" + creatorId + "`", inline: true },
        { name: "Place", value: placeId ? ("https://www.roblox.com/games/" + placeId) : "(tidak diketahui)", inline: false },
      ],
      timestamp: new Date().toISOString(),
    }],
  };
  try {
    await fetch(s.discordWebhook, { method: "POST", headers: { "content-type": "application/json" }, body: JSON.stringify(payload) });
  } catch (e) {}
}

// ---------- bot Discord: command /own ----------
function hexToBytes(hex) {
  const arr = new Uint8Array(hex.length / 2);
  for (let i = 0; i < arr.length; i++) arr[i] = parseInt(hex.substr(i * 2, 2), 16);
  return arr;
}
async function verifyDiscordSignature(bodyText, sigHex, tsRaw, publicKeyHex) {
  try {
    const key = await crypto.subtle.importKey("raw", hexToBytes(publicKeyHex), { name: "Ed25519" }, false, ["verify"]);
    const data = new TextEncoder().encode(tsRaw + bodyText);
    const sig = hexToBytes(sigHex);
    return await crypto.subtle.verify("Ed25519", key, sig, data);
  } catch (e) { return false; }
}

async function handleDiscordInteraction(request, env, ctx) {
  const sig = request.headers.get("x-signature-ed25519");
  const ts = request.headers.get("x-signature-timestamp");
  const bodyText = await request.text();
  if (!sig || !ts || !env.DISCORD_PUBLIC_KEY) return new Response("unauthorized", { status: 401 });
  const valid = await verifyDiscordSignature(bodyText, sig, ts, env.DISCORD_PUBLIC_KEY);
  if (!valid) return new Response("invalid signature", { status: 401 });

  let body;
  try { body = JSON.parse(bodyText); } catch { return new Response("bad request", { status: 400 }); }

  if (body.type === 1) return json({ type: 1 }); // PING dari Discord

  if (body.type === 2 && body.data && body.data.name === "own") {
    const opt = (body.data.options || []).find((o) => o.name === "akun");
    const target = opt ? String(opt.value) : "";
    const appId = env.DISCORD_APPLICATION_ID || body.application_id;
    ctx.waitUntil(handleOwnCommand(env, appId, body.token, target));
    // Balasan langsung "sedang diproses" (otomatis tampil sebagai reply ke command user).
    return json({ type: 5 });
  }

  if (body.type === 2 && body.data && body.data.name === "products") {
    const appId = env.DISCORD_APPLICATION_ID || body.application_id;
    ctx.waitUntil(handleProductsCommand(env, appId, body.token));
    return json({ type: 5 });
  }

  return json({ type: 4, data: { content: "Command tidak dikenal." } });
}

async function handleOwnCommand(env, appId, token, target) {
  let payload;
  try {
    const resolved = await resolveTarget(target);
    if (!resolved.found) {
      payload = { content: "Tidak ditemukan akun Roblox untuk `" + target + "`. Pastikan username atau User ID benar." };
    } else {
      const db = await loadDB(env);
      const owned = productsOwnedBy(db, resolved.userId);
      const lines = owned.map((o) => "\u27a4 " + o.name + (o.active ? "" : " _(nonaktif)_"));
      const embed = {
        title: resolved.username,
        url: "https://www.roblox.com/users/" + resolved.userId + "/profile",
        color: 5793266,
        thumbnail: isHttpUrl(resolved.avatarUrl) ? { url: resolved.avatarUrl } : undefined,
        fields: [
          { name: "User ID", value: "`" + resolved.userId + "`", inline: true },
          { name: "Jumlah produk", value: String(owned.length), inline: true },
        ],
        description: owned.length ? lines.join("\n") : "Belum memiliki lisensi produk apa pun.",
      };
      payload = { embeds: [embed] };
    }
  } catch (e) {
    payload = { content: "Terjadi kesalahan saat memeriksa lisensi. Coba lagi." };
  }
  await editOriginal(appId, token, payload);
}

// ---------- bot Discord: command /products ----------
async function handleProductsCommand(env, appId, token) {
  try {
    const db = await loadDB(env);
    const pids = Object.keys(db.products || {});
    if (pids.length === 0) {
      await editOriginal(appId, token, { content: "Belum ada produk yang tersedia." });
      return;
    }
    // urutkan berdasar tanggal dibuat (terbaru dulu)
    pids.sort((a, b) => String(db.products[b].createdAt || "").localeCompare(String(db.products[a].createdAt || "")));
    const embeds = pids.map((pid) => productEmbed(db.products[pid]));
    // Discord: maks 10 embed per pesan. Kirim 10 pertama via edit, sisanya via follow-up.
    const first = embeds.slice(0, 10);
    await editOriginal(appId, token, { embeds: first });
    for (let i = 10; i < embeds.length; i += 10) {
      await followUp(appId, token, { embeds: embeds.slice(i, i + 10) });
    }
  } catch (e) {
    await editOriginal(appId, token, { content: "Terjadi kesalahan saat mengambil daftar produk." });
  }
}

// bentuk 1 embed untuk sebuah produk (dipakai /products)
function productEmbed(p) {
  const owners = Object.keys((p && p.users) || {}).length;
  const created = p && p.createdAt ? new Date(p.createdAt) : null;
  const releaseStr = created ? "<t:" + Math.floor(created.getTime() / 1000) + ":D>" : "-";
  const fields = [
    { name: "Tanggal rilis", value: releaseStr, inline: true },
    { name: "Jumlah pemilik", value: String(owners), inline: true },
    { name: "Harga", value: (p && p.price) ? p.price : "-", inline: true },
  ];
  const embed = {
    title: (p && p.name) || "Produk",
    color: 5793266,
    fields,
  };
  if (p && isHttpUrl(p.link)) embed.url = p.link.trim();      // judul jadi bisa diklik
  if (p && p.description) embed.description = p.description;
  if (p && isHttpUrl(p.imageUrl)) embed.thumbnail = { url: p.imageUrl.trim() };
  return embed;
}

// edit balasan awal (setelah defer type 5)
async function editOriginal(appId, token, payload) {
  try {
    await fetch("https://discord.com/api/v10/webhooks/" + appId + "/" + token + "/messages/@original", {
      method: "PATCH",
      headers: { "content-type": "application/json" },
      body: JSON.stringify(payload),
    });
  } catch (e) {}
}
// kirim pesan tambahan (untuk daftar produk > 10)
async function followUp(appId, token, payload) {
  try {
    await fetch("https://discord.com/api/v10/webhooks/" + appId + "/" + token, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify(payload),
    });
  } catch (e) {}
}

